import * as React from "react";

import { cn } from "@/lib/utils";

import "./squeeze-animation.css";

type SqueezeAnimationValue = number | string;

export type SqueezeOptions = {
  /** Horizontal rebound distance. Numeric values are converted to px. Set to 0 to disable. */
  shakeX?: SqueezeAnimationValue;
  /** Vertical rebound distance. Numeric values are converted to px. Set to 0 to disable. */
  shakeY?: SqueezeAnimationValue;
  /** Animation duration. Numeric values are converted to ms. */
  duration?: SqueezeAnimationValue;
};

export type SqueezeProps = React.ComponentPropsWithoutRef<"span"> &
  SqueezeOptions & {
    /** Classes applied to the animated child wrapper. */
    targetClassName?: string;
  };

export function Squeeze({
  className,
  children,
  duration,
  shakeX,
  shakeY,
  style,
  targetClassName,
  ...props
}: SqueezeProps) {
  return (
    <span
      data-slot="squeeze"
      className={cn("squeeze-animation inline-flex", className)}
      style={getSqueezeAnimationStyle({ duration, shakeX, shakeY }, style)}
      {...props}
    >
      <span
        data-slot="squeeze-target"
        className={cn("squeeze-animation-target inline-flex", targetClassName)}
      >
        {children}
      </span>
    </span>
  );
}

export type SqueezeAnimationProps = React.ComponentPropsWithoutRef<"div"> &
  SqueezeOptions & {
    /** Classes applied to the animated SVG group. */
    targetClassName?: string;
  };

export function SqueezeAnimation({
  className,
  duration,
  shakeX,
  shakeY,
  style,
  targetClassName,
  ...props
}: SqueezeAnimationProps) {
  return (
    <div
      data-slot="squeeze-animation"
      className={cn(
        "squeeze-animation flex flex-col items-center text-foreground",
        className,
      )}
      style={getSqueezeAnimationStyle({ duration, shakeX, shakeY }, style)}
      {...props}
    >
      <svg
        viewBox="0 0 100 100"
        aria-hidden="true"
        className="squeeze-animation-svg h-auto w-full max-w-80"
      >
        <g
          data-slot="squeeze-animation-target"
          className={cn(
            "squeeze-animation-target squeeze-animation-icon",
            targetClassName,
          )}
        >
          <rect
            x="26"
            y="30"
            width="48"
            height="40"
            rx="12"
            fill="currentColor"
            fillOpacity="0.1"
            stroke="currentColor"
            strokeWidth="6"
          />
          <path
            d="M 38 46 H 62"
            fill="none"
            stroke="currentColor"
            strokeLinecap="round"
            strokeWidth="6"
          />
          <path
            d="M 38 58 H 54"
            fill="none"
            stroke="currentColor"
            strokeLinecap="round"
            strokeWidth="6"
          />
        </g>
      </svg>
    </div>
  );
}

function getSqueezeAnimationStyle(
  {
    duration,
    shakeX,
    shakeY,
  }: Pick<SqueezeOptions, "duration" | "shakeX" | "shakeY">,
  style: React.CSSProperties | undefined,
) {
  if (duration === undefined && shakeX === undefined && shakeY === undefined) {
    return style;
  }

  return {
    ...style,
    ...(duration !== undefined
      ? { "--squeeze-animation-duration": formatDurationValue(duration) }
      : {}),
    ...(shakeX !== undefined
      ? { "--squeeze-animation-shake-x": formatShakeValue(shakeX) }
      : {}),
    ...(shakeY !== undefined
      ? { "--squeeze-animation-shake-y": formatShakeValue(shakeY) }
      : {}),
  } as React.CSSProperties;
}

function formatShakeValue(value: SqueezeAnimationValue | undefined) {
  return typeof value === "number" ? `${value}px` : value;
}

function formatDurationValue(value: SqueezeAnimationValue | undefined) {
  return typeof value === "number" ? `${value}ms` : value;
}

.squeeze-animation {
  --squeeze-animation-duration: 1500ms;
  --squeeze-animation-ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  --squeeze-animation-rebound-ease: cubic-bezier(0.34, 1.56, 0.64, 1);
  --squeeze-animation-settle-ease: cubic-bezier(0.34, 1.16, 0.64, 1);
  --squeeze-animation-shake-x: 5px;
  --squeeze-animation-shake-y: 3px;
}

.squeeze-animation-target,
.squeeze-animation-icon {
  backface-visibility: hidden;
  transform-origin: center;
  animation: squeeze-animation var(--squeeze-animation-duration) both;
  will-change: transform;
}

.squeeze-animation-svg .squeeze-animation-target,
.squeeze-animation-icon {
  transform-box: fill-box;
}

@keyframes squeeze-animation {
  0% {
    transform: translate(0, 0) scale(1);
    animation-timing-function: var(--squeeze-animation-ease-out);
  }
  8% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.06),
        calc(var(--squeeze-animation-shake-y) * 0.1)
      )
      scale(1.08, 0.92);
    animation-timing-function: var(--squeeze-animation-ease-out);
  }
  17% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.16),
        calc(var(--squeeze-animation-shake-y) * 0.24)
      )
      scale(1.2, 0.8);
    animation-timing-function: var(--squeeze-animation-ease-out);
  }
  29% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.32),
        calc(var(--squeeze-animation-shake-y) * 0.4)
      )
      scale(1.34, 0.68);
    animation-timing-function: var(--squeeze-animation-ease-out);
  }
  34% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.36),
        calc(var(--squeeze-animation-shake-y) * 0.44)
      )
      scale(1.38, 0.64);
    animation-timing-function: var(--squeeze-animation-rebound-ease);
  }
  42% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * 1.25),
        calc(var(--squeeze-animation-shake-y) * -1.25)
      )
      scale(0.72, 1.32);
    animation-timing-function: var(--squeeze-animation-rebound-ease);
  }
  52% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.9),
        calc(var(--squeeze-animation-shake-y) * 0.78)
      )
      scale(1.22, 0.8);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  61% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * 0.62),
        calc(var(--squeeze-animation-shake-y) * -0.58)
      )
      scale(0.88, 1.13);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  69% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.38),
        calc(var(--squeeze-animation-shake-y) * 0.36)
      )
      scale(1.11, 0.91);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  76% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * 0.22),
        calc(var(--squeeze-animation-shake-y) * -0.22)
      )
      scale(0.96, 1.045);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  82% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.14),
        calc(var(--squeeze-animation-shake-y) * 0.14)
      )
      scale(1.04, 0.97);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  87% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * 0.09),
        calc(var(--squeeze-animation-shake-y) * -0.09)
      )
      scale(0.985, 1.02);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  91% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.06),
        calc(var(--squeeze-animation-shake-y) * 0.06)
      )
      scale(1.018, 0.99);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  95% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * 0.03),
        calc(var(--squeeze-animation-shake-y) * -0.035)
      )
      scale(0.995, 1.007);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  98% {
    transform: translate(
        calc(var(--squeeze-animation-shake-x) * -0.015),
        calc(var(--squeeze-animation-shake-y) * 0.018)
      )
      scale(1.004, 0.998);
    animation-timing-function: var(--squeeze-animation-settle-ease);
  }
  100% {
    transform: translate(0, 0) scale(1);
  }
}

@media (prefers-reduced-motion: reduce) {
  .squeeze-animation-target,
  .squeeze-animation-icon {
    animation: none;
    will-change: auto;
  }
}
